import React, { useState, useRef } from 'react';
import { ArrowLeft, Upload, Scissors, Play, Download, Loader2, Video, CheckCircle, Smartphone } from 'lucide-react';

interface VideoSplitterProps {
    onBack: () => void;
}

interface SplitChunk {
    id: string;
    url: string;
    duration: number;
    part: number;
}

const VideoSplitter: React.FC<VideoSplitterProps> = ({ onBack }) => {
    const [videoFile, setVideoFile] = useState<File | null>(null);
    const [videoUrl, setVideoUrl] = useState<string | null>(null);
    const [chunks, setChunks] = useState<SplitChunk[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [progress, setProgress] = useState('');
    const [segmentDuration, setSegmentDuration] = useState(15);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setVideoFile(file);
            setVideoUrl(URL.createObjectURL(file));
            setChunks([]);
        }
    };

    const processVideo = async () => {
        if (!videoFile || !videoUrl) return;

        setIsProcessing(true);
        setChunks([]);

        // Setup hidden elements
        const video = document.createElement('video');
        video.src = videoUrl;
        video.muted = false; // We want audio
        video.volume = 1.0;
        video.playsInline = true;

        await new Promise(r => video.onloadedmetadata = r);

        const canvas = document.createElement('canvas');
        canvas.width = 720;
        canvas.height = 1280; // 9:16 Ratio
        const ctx = canvas.getContext('2d');

        if (!ctx) return;

        // Setup Audio Context
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
        if (audioCtx.state === 'suspended') await audioCtx.resume();

        const source = audioCtx.createMediaElementSource(video);
        const dest = audioCtx.createMediaStreamDestination();
        source.connect(dest);

        const totalSegments = Math.ceil(video.duration / segmentDuration);
        const generatedChunks: SplitChunk[] = [];

        for (let i = 0; i < totalSegments; i++) {
            setProgress(`Processing Part ${i + 1} of ${totalSegments}...`);

            const chunkStartTime = i * segmentDuration;
            const chunkEndTime = Math.min((i + 1) * segmentDuration, video.duration);
            const duration = chunkEndTime - chunkStartTime;

            // Seek
            video.currentTime = chunkStartTime;
            await new Promise(r => {
                const onSeek = () => {
                    video.removeEventListener('seeked', onSeek);
                    r(true);
                };
                video.addEventListener('seeked', onSeek);
            });

            // Stream Setup
            const videoStream = canvas.captureStream(30);
            const combinedStream = new MediaStream([
                ...videoStream.getVideoTracks(),
                ...dest.stream.getAudioTracks()
            ]);

            const recorder = new MediaRecorder(combinedStream, {
                mimeType: 'video/webm;codecs=vp9,opus',
                videoBitsPerSecond: 2500000 // 2.5 Mbps
            });

            const dataChunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data.size > 0) dataChunks.push(e.data);
            };

            const chunkPromise = new Promise<string>((resolve) => {
                recorder.onstop = () => {
                    const blob = new Blob(dataChunks, { type: 'video/webm' });
                    resolve(URL.createObjectURL(blob));
                };
            });

            recorder.start();
            video.play();

            // Render Loop for this segment
            const stopTime = chunkEndTime;

            await new Promise((resolveRender) => {
                const draw = () => {
                    if (video.currentTime >= stopTime || video.ended) {
                        recorder.stop();
                        video.pause();
                        resolveRender(true);
                        return;
                    }

                    // 9:16 Crop Logic (Center Cover)
                    ctx.fillStyle = '#000';
                    ctx.fillRect(0, 0, canvas.width, canvas.height);

                    const vRatio = video.videoWidth / video.videoHeight;
                    const cRatio = canvas.width / canvas.height;
                    let dw, dh, dx, dy;

                    if (vRatio > cRatio) {
                        // Video is wider (landscape or wider portrait) -> Crop sides
                        dh = canvas.height;
                        dw = dh * vRatio;
                        dx = (canvas.width - dw) / 2;
                        dy = 0;
                    } else {
                        // Video is taller -> Crop top/bottom
                        dw = canvas.width;
                        dh = dw / vRatio;
                        dx = 0;
                        dy = (canvas.height - dh) / 2;
                    }
                    ctx.drawImage(video, dx, dy, dw, dh);

                    requestAnimationFrame(draw);
                };
                draw();
            });

            const chunkUrl = await chunkPromise;
            generatedChunks.push({
                id: Math.random().toString(),
                url: chunkUrl,
                duration: duration,
                part: i + 1
            });
            setChunks([...generatedChunks]); // Update UI incrementally
        }

        audioCtx.close();
        setIsProcessing(false);
        setProgress('Done!');
    };

    const downloadChunk = (chunk: SplitChunk) => {
        const a = document.createElement('a');
        a.href = chunk.url;
        a.download = `part-${chunk.part}-video.webm`;
        a.click();
    };

    return (
        <div className="min-h-screen bg-slate-950 text-white font-inter flex flex-col">
            {/* Header */}
            <div className="bg-pink-600/10 border-b border-pink-500/20 p-4 sticky top-0 z-20 flex items-center justify-between backdrop-blur-md">
                <div className="flex items-center gap-4">
                    <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-full transition-colors text-slate-400 hover:text-white">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-pink-400 to-rose-500 bg-clip-text text-transparent flex items-center gap-2">
                        <Scissors className="w-6 h-6 text-pink-500" />
                        Auto Video Splitter
                    </h1>
                </div>
            </div>

            <div className="flex-1 max-w-5xl w-full mx-auto p-6 space-y-8">

                {/* Input Section */}
                <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl space-y-6">
                    <div className="flex flex-col md:flex-row gap-6">
                        {/* Video Upload */}
                        <div className="flex-1 space-y-4">
                            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest block">Upload Video</label>
                            <div 
                                onClick={() => fileInputRef.current?.click()}
                                className={`aspect-video w-full bg-slate-950 rounded-xl border-2 border-dashed flex flex-col items-center justify-center cursor-pointer transition-all relative overflow-hidden group ${videoUrl ? 'border-pink-500/50' : 'border-slate-700 hover:border-pink-500/50'}`}
                            >
                                <input type="file" accept="video/*" ref={fileInputRef} className="hidden" onChange={handleFileUpload} />
                                {videoUrl ? (
                                    <video src={videoUrl} className="w-full h-full object-contain" />
                                ) : (
                                    <div className="text-center p-6 text-slate-500 group-hover:text-pink-400 transition-colors">
                                        <Video className="w-12 h-12 mx-auto mb-3 opacity-50" />
                                        <p className="text-sm font-medium">Click to upload video</p>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Config & Action */}
                        <div className="w-full md:w-80 space-y-6 flex flex-col justify-center">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-500 uppercase">Segment Duration (Sec)</label>
                                <input 
                                    type="number" 
                                    value={segmentDuration}
                                    onChange={(e) => setSegmentDuration(Number(e.target.value))}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white font-mono text-center focus:ring-2 focus:ring-pink-500 outline-none"
                                />
                            </div>

                            <div className="p-4 bg-pink-900/10 border border-pink-500/20 rounded-xl">
                                <p className="text-xs text-pink-300 flex items-center gap-2">
                                    <Smartphone className="w-4 h-4" /> Output Format: <strong>9:16 (Vertical)</strong>
                                </p>
                                <p className="text-[10px] text-slate-500 mt-1 pl-6">
                                    Video will be automatically center-cropped to fit vertical screens.
                                </p>
                            </div>

                            <button 
                                onClick={processVideo}
                                disabled={!videoUrl || isProcessing}
                                className="w-full py-4 bg-pink-600 hover:bg-pink-500 disabled:bg-slate-800 disabled:text-slate-500 text-white rounded-xl font-bold shadow-lg shadow-pink-900/20 transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                                {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
                                {isProcessing ? 'Processing...' : 'Start Splitting'}
                            </button>

                            {isProcessing && (
                                <p className="text-xs text-center text-pink-400 animate-pulse font-mono">{progress}</p>
                            )}
                        </div>
                    </div>
                </div>

                {/* Results Section */}
                {chunks.length > 0 && (
                    <div className="space-y-4 pb-20">
                        <h2 className="text-lg font-bold text-slate-400 flex items-center gap-2">
                            <CheckCircle className="w-5 h-5 text-green-500" /> Generated Segments ({chunks.length})
                        </h2>

                        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                            {chunks.map((chunk) => (
                                <div key={chunk.id} className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden group animate-in fade-in slide-in-from-bottom-4 duration-500">
                                    <div className="aspect-[9/16] bg-black relative">
                                        <video src={chunk.url} className="w-full h-full object-cover" controls />
                                    </div>
                                    <div className="p-3">
                                        <div className="flex justify-between items-center mb-3">
                                            <span className="text-sm font-bold text-white">Part {chunk.part}</span>
                                            <span className="text-[10px] bg-slate-800 px-2 py-0.5 rounded text-slate-400">{chunk.duration.toFixed(1)}s</span>
                                        </div>
                                        <button 
                                            onClick={() => downloadChunk(chunk)}
                                            className="w-full py-2 bg-slate-800 hover:bg-green-600 text-slate-300 hover:text-white rounded-lg text-xs font-bold transition-colors flex items-center justify-center gap-2"
                                        >
                                            <Download className="w-3 h-3" /> Download
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default VideoSplitter;

import React, { useState, useRef } from 'react';
import { ArrowLeft, Search, Download, Trash2, ExternalLink, FileSpreadsheet, Plus, Globe, Loader2, StopCircle, Layers, Image as ImageIcon } from 'lucide-react';
import { ScrapedArticle } from '../types';
import * as XLSX from 'xlsx';

interface ScraperProps {
  onBack: () => void;
}

const Scraper: React.FC<ScraperProps> = ({ onBack }) => {
  const [urlInput, setUrlInput] = useState('');
  const [articles, setArticles] = useState<ScrapedArticle[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [scanProgress, setScanProgress] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  // Ref to control stopping the loop
  const abortScanRef = useRef<boolean>(false);

  // Helper with timeout to fail fast if proxy hangs
  const fetchWithTimeout = async (url: string, options: RequestInit = {}, timeout = 10000) => {
      const controller = new AbortController();
      const id = setTimeout(() => controller.abort(), timeout);
      try {
          const response = await fetch(url, { ...options, signal: controller.signal });
          clearTimeout(id);
          return response;
      } catch (e) {
          clearTimeout(id);
          throw e;
      }
  };

  const fetchHtmlContent = async (url: string): Promise<string> => {
    // 1. Normalize URL
    let targetUrl = url.trim();
    if (!/^https?:\/\//i.test(targetUrl)) {
        targetUrl = 'https://' + targetUrl;
    }

    // 2. Try CorsProxy.io (Fastest)
    try {
        const response = await fetchWithTimeout(`https://corsproxy.io/?${encodeURIComponent(targetUrl)}`);
        if (response.ok) {
            return await response.text();
        }
    } catch (e) {
        // Continue
    }

    // 3. Try Primary Proxy (AllOrigins) - Robust
    try {
        const response = await fetchWithTimeout(`https://api.allorigins.win/get?url=${encodeURIComponent(targetUrl)}`);
        if (response.ok) {
            const data = await response.json();
            if (data.contents) return data.contents;
        }
    } catch (e) {
        // Continue
    }

    // 4. Try Secondary Proxy (CodeTabs)
    try {
        const response = await fetchWithTimeout(`https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(targetUrl)}`);
        if (response.ok) {
            return await response.text();
        }
    } catch (e) {
        // Continue
    }

    throw new Error('Could not fetch content (Blocked/Timeout).');
  };

  const resolveUrl = (baseUrl: string, relativeUrl: string): string => {
      if (!relativeUrl) return '';
      if (relativeUrl.startsWith('data:')) return relativeUrl; // Keep base64

      try {
          return new URL(relativeUrl, baseUrl).href;
      } catch (e) {
          return relativeUrl;
      }
  };

  const extractArticleData = (htmlContent: string, pageUrl: string): ScrapedArticle => {
      const parser = new DOMParser();
      const doc = parser.parseFromString(htmlContent, 'text/html');

      const cleanText = (text: string) => text.replace(/\s+/g, ' ').trim();

      // 1. Title Extraction
      const ogTitle = doc.querySelector('meta[property="og:title"]')?.getAttribute('content');
      const twitterTitle = doc.querySelector('meta[name="twitter:title"]')?.getAttribute('content');
      const h1 = doc.querySelector('h1')?.innerText;
      const title = cleanText(ogTitle || twitterTitle || h1 || doc.title || 'No Title Found');

      // 2. Description / Content Extraction
      let finalDescription = '';

      // Strategy A: JSON-LD (Structured Data)
      const jsonLdScripts = doc.querySelectorAll('script[type="application/ld+json"]');
      for (const script of jsonLdScripts) {
          try {
              const json = JSON.parse(script.textContent || '{}');
              const obj = Array.isArray(json) ? json[0] : json;
              if (obj && (obj['@type'] === 'NewsArticle' || obj['@type'] === 'Article' || obj['@type'] === 'BlogPosting')) {
                  if (obj.description) {
                      finalDescription = cleanText(obj.description);
                  } else if (obj.articleBody) {
                      finalDescription = cleanText(obj.articleBody.substring(0, 300)) + '...';
                  }
                  if (finalDescription) break;
              }
          } catch (e) { /* ignore */ }
      }

      // Strategy B: Text Scraper (Prioritize Body Text over Meta Description if possible)
      if (!finalDescription) {
          // Find the most likely content container
          const candidates = Array.from(doc.querySelectorAll('article, [role="main"], .post-content, .entry-content, .article-body, #content, main'));
          let contentContainer = candidates.length > 0 ? candidates[0] : doc.body;

          const paragraphs = Array.from(contentContainer.querySelectorAll('p'));

          for (const p of paragraphs) {
              const text = cleanText(p.innerText);
              if (text.length > 50 && !text.toLowerCase().includes('copyright') && !text.toLowerCase().includes('all rights reserved')) {
                  finalDescription = text;
                  break;
              }
          }
      }

      // Strategy C: Meta Description Fallback
      if (!finalDescription) {
          const ogDesc = doc.querySelector('meta[property="og:description"]')?.getAttribute('content');
          const twitterDesc = doc.querySelector('meta[name="twitter:description"]')?.getAttribute('content');
          const metaDesc = doc.querySelector('meta[name="description"]')?.getAttribute('content');
          finalDescription = cleanText(ogDesc || twitterDesc || metaDesc || '');
      }

      if (!finalDescription) finalDescription = "No description found";

      // 3. Image (Enhanced Logic)
      let imgUrl = '';

      // Priority A: Meta Tags (Best Quality)
      const metaImage = 
          doc.querySelector('meta[property="og:image"]')?.getAttribute('content') ||
          doc.querySelector('meta[name="twitter:image"]')?.getAttribute('content') ||
          doc.querySelector('link[rel="image_src"]')?.getAttribute('href');

      if (metaImage) {
          imgUrl = metaImage;
      } else {
          // Priority B: Find largest image in article body
          const images = Array.from(doc.querySelectorAll('img'));
          let maxScore = 0;

          for (const img of images) {
              const src = img.getAttribute('src') || 
                          img.getAttribute('data-src') || 
                          img.getAttribute('data-original') ||
                          img.getAttribute('data-url');

              if (!src || src.startsWith('data:')) continue;
              if (src.endsWith('.svg') || src.includes('icon') || src.includes('logo')) continue;

              const width = parseFloat(img.getAttribute('width') || '0');
              const height = parseFloat(img.getAttribute('height') || '0');

              let score = width * height;
              if (width === 0) score = 100; // Give benefit of doubt

              if (score > maxScore) {
                  maxScore = score;
                  imgUrl = src;
              }
          }
      }

      if (imgUrl) {
          imgUrl = resolveUrl(pageUrl, imgUrl);
      }

      return {
        id: Date.now().toString() + Math.random().toString().slice(2, 5),
        url: pageUrl,
        title: title,
        firstParagraph: finalDescription,
        imageUrl: imgUrl
      };
  };

  // Helper for Parallel Processing
  const processUrlQueue = async (urls: string[], concurrency: number) => {
      let currentIndex = 0;
      let completed = 0;
      const total = urls.length;

      const worker = async () => {
          while (currentIndex < total && !abortScanRef.current) {
              const index = currentIndex++;
              const url = urls[index];
              setScanProgress(`Processing ${completed}/${total} ...`);

              try {
                  const htmlContent = await fetchHtmlContent(url);
                  const article = extractArticleData(htmlContent, url);

                  if (article.title && article.title !== 'No Title Found') {
                      setArticles(prev => [article, ...prev]);
                  }
              } catch (err) {
                  console.warn(`Failed: ${url}`);
              } finally {
                  completed++;
                  setScanProgress(`Processed ${completed}/${total}`);
              }
          }
      };

      const workers = Array.from({ length: concurrency }, () => worker());
      await Promise.all(workers);
  };

  const handleBatchScrape = async () => {
    const urls = urlInput.split('\n').map(u => u.trim()).filter(u => u.length > 0);
    if (urls.length === 0) return;

    setIsLoading(true);
    setError(null);
    abortScanRef.current = false;

    // Run 5 requests in parallel (Speed Boost)
    await processUrlQueue(urls, 5);

    setIsLoading(false);
    setScanProgress('');
    if (!abortScanRef.current) {
        setUrlInput(''); 
    }
  };

  const handleHomeScan = async () => {
      const urls = urlInput.split('\n').map(u => u.trim()).filter(u => u.length > 0);
      if (urls.length === 0) return;
      const baseUrlInput = urls[0];

      abortScanRef.current = false;
      setIsLoading(true);
      setError(null);
      setScanProgress('Fetching homepage map...');

      try {
          let baseUrl = baseUrlInput;
          if (!/^https?:\/\//i.test(baseUrl)) baseUrl = 'https://' + baseUrl;

          const homeHtml = await fetchHtmlContent(baseUrl);
          const parser = new DOMParser();
          const doc = parser.parseFromString(homeHtml, 'text/html');

          const anchorTags = Array.from(doc.querySelectorAll('a'));
          const origin = new URL(baseUrl).origin;

          const foundUrls = new Set<string>();
          anchorTags.forEach(a => {
              try {
                  const href = a.getAttribute('href');
                  if (!href) return;
                  if (href.startsWith('#') || href.startsWith('javascript:')) return;

                  const fullUrl = resolveUrl(baseUrl, href);

                  if (fullUrl.startsWith(origin) && 
                      fullUrl !== baseUrl && 
                      fullUrl !== baseUrl + '/' &&
                      !fullUrl.match(/\.(pdf|zip|png|jpg|jpeg|gif|css|js)$/i)) {
                      foundUrls.add(fullUrl);
                  }
              } catch (e) { }
          });

          const linksToScrape = Array.from(foundUrls);

          if (linksToScrape.length === 0) {
              setError('No valid internal links found.');
              setIsLoading(false);
              return;
          }

          // Increased limit due to faster processing
          const maxLimit = 20; 
          const limitedLinks = linksToScrape.slice(0, maxLimit);

          await processUrlQueue(limitedLinks, 5);

      } catch (err: any) {
          setError(err.message || 'Failed to scan homepage.');
      } finally {
          setIsLoading(false);
          setScanProgress('');
      }
  };

  const stopScan = () => {
      abortScanRef.current = true;
      setScanProgress('Stopping...');
  };

  const handleExportExcel = () => {
    if (articles.length === 0) return;
    const headers = ["Judul", "Paragraf Pertama", "URL Gambar"];
    const rows = [...articles].reverse().map(item => [item.title, item.firstParagraph, item.imageUrl]);
    const data = [headers, ...rows];
    const ws = XLSX.utils.aoa_to_sheet(data);
    ws['!cols'] = [{ wch: 50 }, { wch: 100 }, { wch: 50 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Scraped Data");
    XLSX.writeFile(wb, `scraped_articles_${Date.now()}.xlsx`);
  };

  const removeArticle = (id: string) => {
    setArticles(prev => prev.filter(a => a.id !== id));
  };

  const getDisplayImage = (url: string) => {
      if (!url) return null;
      return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=200&h=200&fit=cover`;
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col">

      {/* Header */}
      <div className="bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-20 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-full transition-colors text-slate-400 hover:text-white">
                <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-r from-green-400 to-emerald-500 bg-clip-text text-transparent flex items-center gap-2">
                <FileSpreadsheet className="w-6 h-6 text-green-500" />
                Article Scraper <span className="text-[10px] bg-green-900/50 px-2 py-0.5 rounded text-green-300">Turbo</span>
            </h1>
        </div>

        {articles.length > 0 && (
            <button 
                onClick={handleExportExcel}
                className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 text-sm transition-all shadow-lg shadow-green-900/20"
            >
                <Download className="w-4 h-4" />
                Export Excel ({articles.length})
            </button>
        )}
      </div>

      <div className="flex-1 max-w-5xl w-full mx-auto p-6">

        {/* Input Area */}
        <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl mb-8">
            <label className="block text-sm font-medium text-slate-400 mb-2">Article URLs (One per line)</label>
            <div className="flex flex-col md:flex-row gap-3">
                <textarea 
                    value={urlInput}
                    onChange={(e) => setUrlInput(e.target.value)}
                    placeholder="https://example.com/article-1&#10;https://example.com/article-2"
                    rows={3}
                    className="flex-1 bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-green-500 outline-none placeholder:text-slate-600 resize-none font-mono text-sm"
                />

                <div className="flex flex-row md:flex-col gap-2 shrink-0">
                    {isLoading ? (
                        <button 
                            onClick={stopScan}
                            className="h-full bg-red-900/50 border border-red-500 text-red-200 hover:bg-red-900 px-6 py-3 rounded-xl font-medium transition-all flex items-center justify-center gap-2"
                        >
                            <StopCircle className="w-5 h-5 animate-pulse" />
                            Stop
                        </button>
                    ) : (
                        <>
                            <button 
                                onClick={handleBatchScrape}
                                disabled={!urlInput.trim()}
                                title="Scrape URLs listed"
                                className="flex-1 bg-slate-800 hover:bg-slate-700 disabled:opacity-50 text-white px-4 py-3 rounded-xl font-medium transition-all flex items-center justify-center gap-2 border border-slate-700 whitespace-nowrap"
                            >
                                <Layers className="w-5 h-5" />
                                Add List
                            </button>
                            <button 
                                onClick={handleHomeScan}
                                disabled={!urlInput.trim()}
                                title="Scan the first URL as a homepage"
                                className="flex-1 bg-green-600 hover:bg-green-500 disabled:opacity-50 text-white px-6 py-3 rounded-xl font-medium transition-all flex items-center justify-center gap-2 shadow-lg shadow-green-900/20 whitespace-nowrap"
                            >
                                <Globe className="w-5 h-5" />
                                Scan Home
                            </button>
                        </>
                    )}
                </div>
            </div>

            {/* Status Messages */}
            {isLoading && scanProgress && (
                <div className="mt-4 flex items-center gap-2 text-blue-400 text-sm bg-blue-500/10 p-3 rounded-lg border border-blue-500/20">
                    <Loader2 className="w-4 h-4 animate-spin" />
                    {scanProgress}
                </div>
            )}

            {error && <p className="text-red-400 text-sm mt-3 flex items-center gap-1">⚠️ {error}</p>}
        </div>

        {/* Results List */}
        <div className="space-y-4">
            <h2 className="text-lg font-semibold text-slate-300 flex items-center gap-2">
                Scraped Items 
                <span className="bg-slate-800 text-slate-400 text-xs px-2 py-1 rounded-full">{articles.length}</span>
            </h2>

            {articles.length === 0 ? (
                <div className="text-center py-20 text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl">
                    <Search className="w-12 h-12 mx-auto mb-4 opacity-50" />
                    <p>No articles scraped yet.</p>
                    <p className="text-sm">Enter URLs above to extract data.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 gap-4">
                    {articles.map((item) => {
                        const displayImg = getDisplayImage(item.imageUrl);
                        return (
                        <div key={item.id} className="bg-slate-900/50 border border-slate-800 rounded-xl p-4 flex gap-4 group hover:border-slate-700 transition-colors animate-slide-up">
                            {/* Image Thumbnail with Proxy */}
                            <div className="w-24 h-24 flex-shrink-0 bg-black rounded-lg overflow-hidden border border-slate-800 relative">
                                {displayImg ? (
                                    <img 
                                        src={displayImg} 
                                        alt="" 
                                        className="w-full h-full object-cover" 
                                        onError={(e) => {
                                            if (item.imageUrl && e.currentTarget.src !== item.imageUrl) {
                                                e.currentTarget.src = item.imageUrl;
                                            } else {
                                                e.currentTarget.style.display = 'none';
                                            }
                                        }}
                                    />
                                ) : (
                                    <div className="w-full h-full flex flex-col items-center justify-center text-slate-700 text-xs gap-1">
                                        <ImageIcon className="w-6 h-6 opacity-50" />
                                        No Img
                                    </div>
                                )}
                            </div>

                            {/* Content */}
                            <div className="flex-1 min-w-0">
                                <h3 className="font-bold text-white text-lg leading-tight mb-2 line-clamp-2">{item.title}</h3>
                                <p className="text-slate-400 text-sm line-clamp-2 mb-3">{item.firstParagraph}</p>
                                <a href={item.url} target="_blank" rel="noopener noreferrer" className="text-xs text-blue-400 hover:underline flex items-center gap-1">
                                    <ExternalLink className="w-3 h-3" /> {item.url}
                                </a>
                            </div>

                            {/* Actions */}
                            <button 
                                onClick={() => removeArticle(item.id)}
                                className="self-start p-2 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors"
                                title="Remove"
                            >
                                <Trash2 className="w-5 h-5" />
                            </button>
                        </div>
                    )})}
                </div>
            )}
        </div>
      </div>
      <style>{`
          @keyframes slide-up {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-up {
            animation: slide-up 0.3s ease-out forwards;
          }
      `}</style>
    </div>
  );
};

