import React, { useState } from 'react';
import { ArrowLeft, Film, Loader2, Play, Download, AlertTriangle, MonitorPlay, Smartphone } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

interface TextToVideoProps {
    onBack: () => void;
}

const TextToVideo: React.FC<TextToVideoProps> = ({ onBack }) => {
    const [prompt, setPrompt] = useState('');
    const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
    const [isGenerating, setIsGenerating] = useState(false);
    const [videoUrl, setVideoUrl] = useState<string | null>(null);
    const [status, setStatus] = useState<string>('');
    const [error, setError] = useState<string | null>(null);

    const handleGenerate = async () => {
        if (!prompt.trim()) return;

        // Veo requires a selected paid project
        if (!(await window.aistudio.hasSelectedApiKey())) {
            try {
                await window.aistudio.openSelectKey();
            } catch (e) {
                setError("API Key selection failed or cancelled.");
                return;
            }
        }

        // Re-check after prompt
        if (!(await window.aistudio.hasSelectedApiKey())) {
             return;
        }

        setIsGenerating(true);
        setVideoUrl(null);
        setError(null);
        setStatus('Initializing Veo 3.1 Fast...');

        try {
            // Must re-init AI with env key which is injected after selection
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            let operation = await ai.models.generateVideos({
                model: 'veo-3.1-fast-generate-preview',
                prompt: prompt,
                config: {
                    numberOfVideos: 1,
                    resolution: '720p', // Lower quality as requested for speed
                    aspectRatio: aspectRatio
                }
            });

            setStatus('Rendering video frames...');

            // Polling loop
            while (!operation.done) {
                await new Promise(resolve => setTimeout(resolve, 5000)); // Poll every 5s
                operation = await ai.operations.getVideosOperation({ operation: operation });
                setStatus('Still rendering (this may take a minute)...');
            }

            const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
            if (downloadLink) {
                setStatus('Finalizing download...');
                // The URI requires the API key appended
                const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
                const blob = await response.blob();
                const url = URL.createObjectURL(blob);
                setVideoUrl(url);
                setStatus('Complete!');
            } else {
                throw new Error("No video URI returned from operation.");
            }

        } catch (err: any) {
            console.error(err);
            if (err.message?.includes("404") || err.message?.includes("not found")) {
                setError("Veo models are currently available in limited regions/projects. Please check your billing project.");
                // Reset key to allow trying another project
                await window.aistudio.openSelectKey(); 
            } else {
                setError(err.message || "Failed to generate video.");
            }
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="min-h-screen bg-slate-950 text-white font-inter flex flex-col">
            {/* Header */}
            <div className="bg-cyan-900/20 border-b border-cyan-500/20 p-4 sticky top-0 z-20 flex items-center justify-between backdrop-blur-md">
                <div className="flex items-center gap-4">
                    <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-full transition-colors text-slate-400 hover:text-white">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-teal-500 bg-clip-text text-transparent flex items-center gap-2">
                        <Film className="w-6 h-6 text-cyan-500" />
                        Text to Video (Veo)
                    </h1>
                </div>
            </div>

            <div className="flex-1 max-w-6xl w-full mx-auto p-4 lg:p-8 flex flex-col lg:flex-row gap-8">

                {/* Left: Controls */}
                <div className="w-full lg:w-1/2 space-y-6">
                    <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl space-y-6">
                        <div className="space-y-3">
                            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest block">Video Prompt</label>
                            <textarea 
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                placeholder="Describe your video in detail (e.g., A cinematic drone shot of a futuristic cyberpunk city at night with neon lights and flying cars)..."
                                className="w-full h-40 bg-slate-950 border border-slate-700 rounded-xl p-4 text-sm focus:ring-2 focus:ring-cyan-500 outline-none resize-none placeholder:text-slate-600"
                            />
                        </div>

                        <div className="space-y-3">
                            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest block">Aspect Ratio</label>
                            <div className="grid grid-cols-2 gap-4">
                                <button 
                                    onClick={() => setAspectRatio('16:9')}
                                    className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${aspectRatio === '16:9' ? 'bg-cyan-500/10 border-cyan-500 text-cyan-400' : 'bg-slate-950 border-slate-700 text-slate-500 hover:border-slate-600'}`}
                                >
                                    <MonitorPlay className="w-6 h-6" />
                                    <span className="text-xs font-bold">16:9 (Landscape)</span>
                                </button>
                                <button 
                                    onClick={() => setAspectRatio('9:16')}
                                    className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${aspectRatio === '9:16' ? 'bg-cyan-500/10 border-cyan-500 text-cyan-400' : 'bg-slate-950 border-slate-700 text-slate-500 hover:border-slate-600'}`}
                                >
                                    <Smartphone className="w-6 h-6" />
                                    <span className="text-xs font-bold">9:16 (Shorts)</span>
                                </button>
                            </div>
                        </div>

                        {error && (
                            <div className="bg-red-500/10 border border-red-500/20 p-4 rounded-xl flex gap-3 text-red-400 text-sm">
                                <AlertTriangle className="w-5 h-5 shrink-0" />
                                <p>{error}</p>
                            </div>
                        )}

                        <button 
                            onClick={handleGenerate}
                            disabled={!prompt.trim() || isGenerating}
                            className="w-full py-4 bg-cyan-600 hover:bg-cyan-500 disabled:bg-slate-800 disabled:text-slate-500 text-white rounded-xl font-bold shadow-lg shadow-cyan-900/20 transition-all active:scale-95 flex items-center justify-center gap-2"
                        >
                            {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Film className="w-5 h-5" />}
                            {isGenerating ? 'Generating Video...' : 'Generate with Veo Fast'}
                        </button>
                    </div>

                    <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 text-xs text-slate-400">
                        <p className="mb-2"><strong>Note:</strong> This tool uses the <code>veo-3.1-fast-generate-preview</code> model.</p>
                        <ul className="list-disc ml-4 space-y-1">
                            <li>Optimized for speed over highest fidelity.</li>
                            <li>Resolution locked to 720p for faster previews.</li>
                            <li>Requires a Google Cloud Project with billing enabled.</li>
                        </ul>
                    </div>
                </div>

                {/* Right: Output */}
                <div className="w-full lg:w-1/2">
                    <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl h-full flex flex-col">
                        <div className="flex items-center justify-between mb-4">
                            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Video Result</label>
                            {status && <span className="text-xs text-cyan-400 animate-pulse">{status}</span>}
                        </div>

                        <div className="flex-1 bg-black rounded-xl overflow-hidden border border-slate-800 relative flex items-center justify-center min-h-[300px]">
                            {videoUrl ? (
                                <video 
                                    src={videoUrl} 
                                    controls 
                                    autoPlay 
                                    loop 
                                    className="w-full h-full object-contain"
                                />
                            ) : (
                                <div className="text-center p-8 text-slate-600">
                                    {isGenerating ? (
                                        <div className="flex flex-col items-center gap-4">
                                            <Loader2 className="w-12 h-12 animate-spin text-cyan-500" />
                                            <p className="text-sm font-medium">Veo is dreaming up your video...</p>
                                        </div>
                                    ) : (
                                        <>
                                            <Film className="w-16 h-16 mx-auto mb-4 opacity-20" />
                                            <p className="text-sm">Enter a prompt to start generating</p>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>

                        {videoUrl && (
                            <div className="mt-4 pt-4 border-t border-slate-800">
                                <a 
                                    href={videoUrl} 
                                    download={`veo-video-${Date.now()}.mp4`}
                                    className="w-full py-3 bg-slate-800 hover:bg-green-600 hover:text-white text-slate-300 rounded-lg font-bold flex items-center justify-center gap-2 transition-all"
                                >
                                    <Download className="w-4 h-4" /> Download Video
                                </a>
                            </div>
                        )}
                    </div>
                </div>

            </div>
        </div>
    );
};

export default TextToVideo;

