                    </h1>
                </div>

                <a 
                    href={FLOW_PROJECT_URL} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="bg-amber-500 hover:bg-amber-400 text-slate-950 px-4 py-2 rounded-lg text-xs font-black flex items-center gap-2 transition-all shadow-lg shadow-amber-500/20"
                >
                    <Zap className="w-4 h-4" />
                    OPEN FLOW PROJECT
                    <ExternalLink className="w-3 h-3" />
